    // 車形目框（中豎自冖下貫）
    線(p => p.M(X(1.7), Z(18.22)).C(X(3.0), Z(18.15), X(5.3), Z(18.22), X(6.3), Z(18.15)), 0.56);
    線(p => p.M(X(1.78), Z(18.25)).L(X(1.77), Z(20.6)), 0.54);
    線(p => p.M(X(6.22), Z(18.17)).L(X(6.23), Z(20.52)), 0.54);
    線(p => p.M(X(1.8), Z(19.36)).L(X(6.2), Z(19.3)), 0.52);
    線(p => p.M(X(1.82), Z(20.6)).L(X(6.21), Z(20.54)), 0.56);
    出(p => p.M(X(3.93), Z(16.95)).L(X(3.95), Z(22.07)), 0.58);
    // 底雙∪疊（右唇高挑）
    出(p => p.M(X(1.56), Z(21.41))
        .C(X(1.36), Z(21.8), X(1.3), Z(22.25), X(1.55), Z(22.5))
        .C(X(1.9), Z(22.72), X(3.2), Z(22.76), X(4.8), Z(22.76))
        .C(X(5.6), Z(22.75), X(6.3), Z(22.6), X(6.55), Z(22.2))
        .C(X(6.68), Z(21.98), X(6.73), Z(21.72), X(6.74), Z(21.48)), 0.58);
    出(p => p.M(X(1.56), Z(23.11))
        .C(X(1.36), Z(23.45), X(1.3), Z(23.9), X(1.6), Z(24.15))
        .C(X(2.0), Z(24.35), X(3.2), Z(24.39), X(4.6), Z(24.39))
        .C(X(5.4), Z(24.38), X(6.1), Z(24.25), X(6.35), Z(23.95))
        .C(X(6.46), Z(23.85), X(6.5), Z(23.77), X(6.52), Z(23.7)), 0.58);
